#include<bits/stdc++.h>
using namespace  std;
int a[105][105];
int b[10005];
bool v[10005];
int n,m;
long long dfs(int x,int y,int step){
    if(y==m){
        return step+a[b[x]][n];
    }else{
        v[x]=1;
        long long ans=1e18;
        for(int i=1;i<=m;i++){
            if(!v[i]){
                ans=min(ans,dfs(i,y+1,step+a[b[x]][b[i]]));
            }
        }
        v[x]=0;
        return ans;
    }
}
int main(){
    cin>>n;

    for(int i=1;i<=n;i++) for(int j=1;j<=n;j++){ cin>>a[i][j];if(i==j) a[i][j]=0;}
    cin>>m;
    for(int i=1;i<=m;i++) cin>>b[i];
    for(int k=1;k<=n;k++) for(int i=1;i<=n;i++) for(int j=1;j<=n;j++) a[i][j]=min(a[i][j],a[i][k]+a[k][j]);
    b[0]=1;
    b[m+1]=n;
    cout<<dfs(0,0,0);
}
